#endif
public struct FfiConverterTypeAmbaCoreFfi: FfiConverter {
    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = AmbaCoreFfi

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> AmbaCoreFfi {
        return AmbaCoreFfi(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: AmbaCoreFfi) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AmbaCoreFfi {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if ptr == nil {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: AmbaCoreFfi, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}

