/**
 * UniFFI-friendly error wrapper.
 *
 * Two variants on purpose:
 *
 * * `Amba { display }` — every "legacy" error from the Rust core (HTTP
 * 400/500 with no envelope, transport failure, init guard, validation,
 * ...). `display` is `AmbaError::to_string()` (the `#[error(...)]`
 * Display string), so language wrappers' existing `codeFromMessage`
 * prefix matchers keep working unchanged. Field is named `display`
 * instead of `message` because UniFFI 0.28's Kotlin bindgen generates
 * a `class Foo(val message: String)` collision with the inherited
 * `kotlin.Exception.message` open property when the field is literally
 * named `message`. `display` is the Rust convention (`Display` trait
 * → Display string), and the swift/kotlin wrappers translate it to
 * the customer-facing `AmbaApiError.message` field at the SDK boundary.
 *
 * * `Structured { status, code, display, details_json }` — emitted when
 * the server returned a structured `{error:{code,message,details?}}`
 * envelope (see [`AmbaError::Structured`]). Native callers can pattern
 * match on this case directly to recover the granular server code
 * (`STREAK_NOT_DEFINED`, `USER_NOT_FOUND`, `INVALID_PAYLOAD`, …)
 * without prefix-matching a Display string. Closes the gap from #156:
 * the WASM bridge has stamped `code`/`details` on the JS Error since
 * then, but UniFFI was still flattening everything to a single Display
 * string, so Swift/Kotlin/etc could only get the granular code by
 * substring-searching `error.message`.
 *
 * `details` arrives as an `Option<serde_json::Value>` on the Rust side
 * but ships across UniFFI as `Option<String>` (a JSON-encoded blob) —
 * UniFFI doesn't have a native bridge for an arbitrary JSON value, and
 * every consumer language already has a JSON parser. Wrappers can
 * `JSONDecoder().decode(...)` / `JSONObject(...)` / `jsonDecode(...)`
 * on demand.
 */
public enum AmbaCoreError {
    case Amba(display: String)
    /**
     * Server returned a structured `{error:{code,message,details?}}`
     * envelope. Pattern-match this variant in native wrappers to surface
     * the granular server `code` directly instead of prefix-matching a
     * Display string.
     */
    case Structured(status: UInt16, code: String, display: String,
                    /* 
                        * JSON-encoded server `details` payload, or `None` if the
                        * server didn't ship one. Wrappers decode on demand.
                        */ detailsJson: String?)
}

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
public struct FfiConverterTypeAmbaCoreError: FfiConverterRustBuffer {
    typealias SwiftType = AmbaCoreError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AmbaCoreError {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return try .Amba(
                display: FfiConverterString.read(from: &buf)
            )

        case 2: return try .Structured(
                status: FfiConverterUInt16.read(from: &buf),
                code: FfiConverterString.read(from: &buf),
                display: FfiConverterString.read(from: &buf),
                detailsJson: FfiConverterOptionString.read(from: &buf)
            )

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AmbaCoreError, into buf: inout [UInt8]) {
        switch value {
        case let .Amba(display):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(display, into: &buf)

        case let .Structured(status, code, display, detailsJson):
            writeInt(&buf, Int32(2))
            FfiConverterUInt16.write(status, into: &buf)
            FfiConverterString.write(code, into: &buf)
            FfiConverterString.write(display, into: &buf)
            FfiConverterOptionString.write(detailsJson, into: &buf)
        }
    }
}

extension AmbaCoreError: Equatable, Hashable {}

extension AmbaCoreError: Foundation.LocalizedError {
    public var errorDescription: String? {
        String(reflecting: self)
    }
}

